# DK VGS.  Varde - Grindsted
#
let vg = path("d3.dk.vgs");

with detail = 3,
     railway = :first :pax :removed
{
    # point.dk.Varde  dk.LES

    with link = "line.dk.VGS" {
        track(:lor,
                vg[:var.yg - 0.1dl, :var.yg] >> 1ms >> 1mt
            ..  vg[:var.xg + 1mt, :gel - 0.49sw]
        );
    }

    with link = "point.dk.Gellerup", railway = :station {
        track(vg[:gel - 0.5sw, :gel + 0.5sw]);
        marker(:right :de.hp, vg[:gel] >> 0.5mt);
        slabel(:bottom, vg[:gel] >> 0.5mt >> 1sh + (1.5dt, 0.5dt),
            "Gellerup"
        );
    }

    with link = "line.dk.VGS" {
        track(vg[:gel + 0.49sw, :gel + 1.71km]);
        line_label(:left:s, vg[:gel + 1.7km] << 0.5mt, "VGS");
        track(vg[:gel + 1.69km, :sko - 0.49sw]);
    }

    with link = "point.dk.Skonager", railway = :station {
        track(vg[:sko - 0.5sw, :sko + 0.5sw]);
        marker(:right :de.hp, vg[:sko] >> 0.5mt);
        slabel(:bottom, vg[:sko] >> 0.5mt >> 1sh + (1.5dt, 0.2dt),
            "Skonager"
        );
    }

    with link = "line.dk.VGS" {
