    }

    with link = "point.dk.Næsbjerg", railway = :station {
        track(vg[:nas - 0.5sw, :nas + 0.5sw]);
        marker(:left :de.bf, vg[:nas] << 0.5mt);
        slabel(:top, vg[:nas] << 0.5mt << 1sh << 0.3dt, "Næsbjerg");
    }

    with link = "line.dk.VGS" {
        track(vg[:nas + 0.49sw, :bil - 0.49sw]);
    }

    with link = "point.dk.Biltoft", railway = :station {
        track(vg[:bil - 0.5sw, :bil + 0.5sw]);
        marker(:left :de.hp, vg[:bil] << 0.5mt);
        slabel(:right, vg[:bil] >> 0.5mt + (1.3dt, 1.8dt), "Biltoft");
    }

    with link = "line.dk.VGS" {
        track(vg[:bil + 0.49sw, :ose - 0.49sw]);
    }

    with link = "point.dk.Øse", railway = :station {
        track(vg[:ose - 0.5sw, :ose + 0.5sw]);
        marker(:right :de.hp, vg[:ose] >> 0.5mt);
        slabel(:right, vg[:ose] >> 0.5mt >> 1sh + (1dt, 2.3dt),
