    with link = "line.dk.VGS" {
        track(vg[:nor + 0.49sw, :bol - 0.49sw]);
    }

    with link = "point.dk.Bolhede", railway = :station {
        track(vg[:bol - 0.5sw, :bol + 0.5sw]);
