        track(vg[:abi + 0.49sw, :gra - 0.49sw]);
    }

    with link = "point.dk.Gravlund", railway = :station {
        track(vg[:gra - 0.5sw, :gra + 0.5sw]);
        marker(:right :de.bf, vg[:gra] >> 0.5mt);
        slabel(:right, vg[:gra] >> 0.5mt >> 1sh + (1dt, 1.5dt),
