        );
    }

    with link = "line.dk.VGS" {
        track(vg[:gra + 0.49sw, :gra + 2.21km]);
        line_label(:left:e, vg[:gra + 2.2km] << 0.5mt, "VGS");
        track(vg[:gra + 2.19km, :ans - 0.49sw]);
    }

    with link = "point.dk.Ansager", railway = :station {
        track(vg[:ans - 0.5sw, :ans + 0.5sw]);
