        slabel(:right, vg[:mok] >> 0.5mt >> 1sh + (1.4dt, 0.7dt),
            "Mølby Kro"
        );
    }

    with link = "line.dk.VGS" {
        track(vg[:mok + 0.49sw, :mol - 0.49sw]);
    }

    with link = "point.dk.Mølby", railway = :station {
        track(vg[:mol - 0.5sw, :mol + 0.5sw]);
        marker(:left :de.bf, vg[:mol] << 0.5mt);
        slabel(:left, vg[:mol] << 0.5mt << 1sh + (-1.5dt, 1.3dt), "Mølby");
    }

    with link = "line.dk.VGS" {
        track(vg[:mol + 0.49sw, :ade - 0.49sw]);
    }

    with link = "point.dk.Adelvej", railway = :station {
        track(vg[:ade - 0.5sw, :ade + 0.5sw]);
