        slabel(:right, vg[:ade] >> 0.5mt >> 1sh + (1.0dt, 1.2dt),
            "Adelvej"
        );
    }

    with link = "line.dk.VGS" {
        track(vg[:ade + 0.49sw, :tyn - 0.49sw]);
    }

    with link = "point.dk.Tyndkær", railway = :station {
        track(vg[:tyn - 0.5sw, :tyn + 0.5sw]);
