    }

    with link = "line.dk.VGS" {
        track(vg[:tyn + 0.49sw, :egg - 0.49sw]);
    }

    with link = "point.dk.Eg", railway = :station {
        track(vg[:egg - 0.5sw, :egg + 0.5sw]);
