        slabel(:left, vg[:byg] << 0.5mt << 1sh + (2.5dt, -1.2dt),       
            "Bygvænget"
        );
    }

    with link = "line.dk.VGS" {
        track(:lor,
                vg[:byg + 0.49sw, :byg + 0.5sw]
            ..  vg[:gri.yv, :gri.yv + 0.1dl] >> 2ms >> 2mt
        );
    }
}

